sql:
SELECT AVG(value) AS average_value
FROM feature_values
WHERE dataset_id = 1;

SELECT name
FROM datasets
ORDER BY created_at DESC;

external_knowledge:
; The term 'most recently accessed' refers to the datasets with the latest 'last_access_date'; 
; 'Comprehensive statistics' include feature counts, average feature values, label counts, average label values, access counts, and unique user counts;
; 'Active datasets' are those with available access logs, indicating some level of user engagement.
